    }
  }
}

mutation UploadAvatar($input: UploadAvatarInput!) {
  users {
    uploadAvatar(input: $input) {
      userId
      avatarUrl
      jobTitle
      bio
      timezone
      role
      credits
      subscriptionPlan
      subscriptionStatus
      createdAt
      updatedAt
    }
  }
}

mutation UpdateUser($input: UpdateUserInput!) {
  users {
    updateUser(input: $input) {
      uuid
      email
      name
    }
  }
}

mutation PromoteToAdmin($input: PromoteToAdminInput!) {
  users {
    promoteToAdmin(input: $input) {
      uuid
      email
      name
      profile {
        role
      }
    }
  }
}

mutation PromoteToSuperAdmin($input: PromoteToSuperAdminInput!) {
  users {
    promoteToSuperAdmin(input: $input) {
      uuid
      email
      name
      profile {
        role
      }
    }
  }
}

input UpdateUserInput {
  name: String
  email: String
}

input UpdateProfileInput {
  jobTitle: String
  bio: String
  timezone: String
  notifications: JSON
}

input UploadAvatarInput {
  fileData: String
  filePath: String
}

# 1. Get current user
query GetMe {
  users {
    user(uuid: "123e4567-e89b-12d3-a456-426614174000") {
      uuid
      email
      name
      profile {
        jobTitle
        bio
        credits
      }
    }
  }
}

# 2. Update profile
mutation UpdateMyProfile {
  users {
    updateProfile(input: {
      jobTitle: "Senior Developer"
      bio: "Passionate about code"
      timezone: "UTC"
    }) {
      userId
      jobTitle
      bio
    }
  }
}

# 3. Upload avatar
mutation UploadMyAvatar {
  users {
    uploadAvatar(input: {
      fileData: "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAA..."
      filename: "profile.png"
    }) {
      userId
      avatarUrl
    }
  }
}

# 4. Update user name
mutation UpdateMyName {
  users {
    updateUser(input: {
      name: "John Updated"
    }) {
      uuid
      name
    }
  }
}

# 5. Admin: List all users
query ListAllUsers {
  users {
    users(limit: 50, offset: 0) {
      uuid
      email
      name
      isActive
    }
  }
}

# 6. Admin: Get user statistics
query GetStats {
  users {
    userStats {
      totalUsers
      activeUsers
      usersByRole {
        role
        count
      }
    }
  }
}

# 7. SuperAdmin: Promote user to Admin
mutation PromoteUserToAdmin {
  users {
    promoteToAdmin(input: {
      userId: "123e4567-e89b-12d3-a456-426614174000"
    }) {
      uuid
      email
      profile {
        role
      }
    }
  }
}

# 8. SuperAdmin: Promote user to SuperAdmin
mutation PromoteUserToSuperAdmin {
  users {
    promoteToSuperAdmin(input: {
      userId: "123e4567-e89b-12d3-a456-426614174000"
    }) {
      uuid
      email
      profile {
        role
      }
    }
  }
}
